<template>
  <div>
    <button class="back" title="Back" @click="goBack">🔙</button>

    <h1 class="Ser_h1">{{ msg }}</h1>

    <div class="page">
      <!-- 顶部统计 -->
      <div class="showInfo">
        题库里共有{{ totalCount }}道，知识题{{ knowledgeCount }}道题目，单词题 {{ vocabCount }}道，
        收藏夹有{{ favoriteCount }}道, 错题集有{{ wrongCount }}道
      </div>

      <!-- 如果题库加载失败，直接提示（防止“白屏不知原因”） -->
      <div v-if="questions.length === 0" class="warnBox">
        ⚠️ 题库未加载到。请检查：
        <div>1) ServiceNowQuestions.json 是否在 src/assets/data/ 下</div>
        <div>2) import 路径是否正确</div>
        <div>3) JSON 是否为有效数组（外层必须是 []）</div>
      </div>

      <!-- 模式切换 -->
      <div class="modul">
        <div class="item" :class="{ active: mode === 'study' }" @click="switchMode('study')">学习模式</div>
        <div class="item" :class="{ active: mode === 'exam' }" @click="switchMode('exam')">考试模式</div>
        <div class="item" :class="{ active: mode === 'wrong' }" @click="switchMode('wrong')">错题集</div>
        <div class="item" :class="{ active: mode === 'favorite' }" @click="switchMode('favorite')">收藏夹</div>
      </div>

      <!-- 选项区 -->
      <div class="optional">
        <label for="question_type">
          题目类型
          <select id="question_type" v-model="questionType">
            <option value="">不做区别</option>
            <option value="knowledge">知识题</option>
            <option value="vocab">单词题</option>
          </select>
        </label>

        <label for="question_count">
          题目数量
          <input
            type="number"
            id="question_count"
            placeholder="请输入数量"
            v-model.number="questionCount"
            min="1"
          />
        </label>

        <button id="confirm" @click="onConfirm">确认</button>
        <button v-if="started" @click="onReset">重置</button>
      </div>

      <!-- ========================= 学习模式 ========================= -->
      <div v-if="started && mode === 'study'" class="questionArea">
        <div class="qHeader">
          <div>题号: {{ currentKnowledge ? currentKnowledge.id : "-" }}</div>
          <div>进度: {{ currentIndex + 1 }} / {{ sessionKnowledgeList.length }}</div>
          <div>当前模式: 学习模式</div>
        </div>

        <!-- 没有题时提示 -->
        <div v-if="!currentKnowledge" class="emptyBox">
          当前没有知识题可做（请检查筛选条件 / 题目数量 / 模式）。
        </div>

        <div v-else class="qBody">
          <div class="qType">题目类型: 知识题</div>
          <div class="qDesc">{{ currentKnowledge.description }}</div>

          <!-- 选择题：支持单选/多选 -->
          <div v-if="hasOptions(currentKnowledge)">
            <div
              v-for="(text, key) in currentKnowledge.options"
              :key="key"
              class="optRow"
              :class="{ picked: selectedOptions.includes(String(key)), disabled: kgSubmitted }"
              @click="toggleOption(String(key))"
            >
              {{ key }}. {{ text }}
            </div>

            <div class="tips">
              <span v-if="isMultiChoice">✅ 多选题（可选多个）</span>
              <span v-else>✅ 单选题（只能选一个）</span>
            </div>
          </div>

          <!-- 填空题 -->
          <div v-else class="fillArea">
            <input
              type="text"
              v-model="knowledgeInput"
              placeholder="请输入你的答案"
              :disabled="kgSubmitted"
            />
          </div>

          <!-- 操作按钮 -->
          <div class="qActions">
            <button @click="submitKnowledge" :disabled="kgSubmitted || !canSubmitKnowledge">提交</button>

            <button @click="toggleFavoriteKnowledge(currentKnowledge.id)">
              {{ isFavKnowledge(currentKnowledge.id) ? "★ 已收藏" : "☆ 收藏" }}
            </button>

            <span v-if="kgSubmitted" class="result" :class="{ ok: kgIsCorrect, ng: kgIsCorrect === false }">
              {{ kgIsCorrect ? "✅ 正确" : "❌ 错误" }}
            </span>
          </div>

          <!-- 解析 + 实操 -->
          <div v-if="kgSubmitted" class="solution">
            <div class="solTitle">{{ currentKnowledge.solutionTitle || "解析" }}</div>
            <pre class="solText">{{ currentKnowledge.solutionText || showAnswerText(currentKnowledge) }}</pre>

            <div v-if="(currentKnowledge.real_samp_descriptions || []).length" class="real-sample-title">
              实操例子
            </div>

            <div
              
              v-for="(step, index) in (currentKnowledge.real_samp_descriptions || [])"
              :key="index"
              class="real-sample-item"
            >
              <div class="real-step-text">{{ index + 1 }}. {{ step }}</div>

              <img
                v-if="(currentKnowledge.real_samp_descriptions_img || [])[index]"
                class="real-step-img"
                :src="`/csaSamImg/${(currentKnowledge.real_samp_descriptions_img || [])[index]}`"
                alt="real sample step image"
              />
            </div>
          </div>

          <!-- 关联单词题 -->
          <div class="qTools">
            <label>
              <input type="checkbox" v-model="showRelatedVocab" />
              显示关联单词题
            </label>
          </div>

          <div v-if="showRelatedVocab" class="vocabArea">
            <div v-if="relatedVocabList.length === 0">没有关联单词题</div>

            <div v-for="v in relatedVocabList" :key="v.id" class="vocabItem">
              <div class="vHead">
                <div>单词题号: {{ v.id }}</div>
                <button @click="toggleFavoriteVocab(v.id)">
                  {{ isFavVocab(v.id) ? "★ 已收藏" : "☆ 收藏" }}
                </button>
              </div>

              <div class="vDesc">{{ v.description }}</div>

              <div v-if="hasOptions(v)">
                <div v-for="(text, key) in v.options" :key="key">{{ key }}. {{ text }}</div>
              </div>

              <div v-else class="vInputLine">
                <label>
                  拆词输入
                  <input
                    class="EnCheck"
                    type="text"
                    :placeholder="`例子: ag/做 ent/人或物 agent/做事的人 管理者`"
                    v-model="vocabInputs[v.id]"
                  />
                </label>

                <button @click="peekAnswer(v.id)">
                  {{ peekVocab[v.id] ? "隐藏答案" : "偷看答案" }}
                </button>

                <div v-if="peekVocab[v.id]" class="vAnswer">
                  <div>参考答案：</div>
                  <pre>{{ formatVocabAnswer(v.answer) }}</pre>
                  <div v-if="v.solutionText">
                    <pre>{{ v.solutionText }}</pre>
                  </div>
                </div>
              </div>
            </div>
          </div>

          <!-- 上一题下一题 -->
          <div class="qNav">
            <button @click="preQuestion" :disabled="currentIndex === 0">上一题</button>
            <button @click="nextQuestion" :disabled="currentIndex >= sessionKnowledgeList.length - 1">下一题</button>
          </div>
        </div>
      </div>

      <!-- ========================= 其它模式：exam / wrong / favorite ========================= -->
      <div v-if="started && mode !== 'study'" class="questionArea">
        <div class="qHeader">
          <div>当前模式: {{ modeText }}</div>
          <div>本次题目数: {{ sessionKnowledgeList.length }}</div>
        </div>

        <div class="listArea">
          <div v-if="sessionKnowledgeList.length === 0">当前没有题目</div>

          <div v-for="q in sessionKnowledgeList" :key="q.id" class="listItem">
            <div class="listTop">
              <div>
                {{ q.id }}
                <span class="tag">{{ q.type === 0 ? "知识" : "单词" }}</span>
              </div>

              <div class="listBtns">
                <button v-if="q.type === 0" @click="jumpToKnowledge(q.id)">去做这题</button>

                <button v-if="q.type === 0" @click="toggleFavoriteKnowledge(q.id)">
                  {{ isFavKnowledge(q.id) ? "★" : "☆" }}
                </button>

                <button v-if="q.type === 1" @click="toggleFavoriteVocab(q.id)">
                  {{ isFavVocab(q.id) ? "★" : "☆" }}
                </button>
              </div>
            </div>

            <div class="listDesc">{{ q.description }}</div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import questionsJson from "@/assets/data/ServiceNowQuestions.json";

const FAVORITE_KG_KEY = "SN_CSA_FAVORITES_KNOWLEDGE";
const FAVORITE_VOC_KEY = "SN_CSA_FAVORITES_VOCAB";
const WRONG_KG_KEY = "SN_CSA_WRONG_KNOWLEDGE";

export default {
  name: "ServiceNowQuiz",
  props: { msg: String },
  data() {
    return {
      questions: [],

      questionType: "",
      questionCount: null,

      started: false,
      mode: "study",

      sessionList: [],
      sessionKnowledgeList: [],

      currentIndex: 0,
      showRelatedVocab: false,

      selectedOptions: [],
      knowledgeInput: "",
      kgSubmitted: false,
      kgIsCorrect: null,

      vocabInputs: {},
      peekVocab: {},

      favKg: [],
      favVoc: [],
      favoriteCount: 0,
      wrongCount: 0,
    };
  },
  computed: {
    currentKnowledge() {
      return this.sessionKnowledgeList[this.currentIndex] || null;
    },

    isMultiChoice() {
      if (!this.currentKnowledge) return false;
      return Array.isArray(this.currentKnowledge.answer) && this.currentKnowledge.answer.length > 1;
    },

    knowledgeQuestions() {
      return this.questions.filter((q) => q.type === 0);
    },
    vocabQuestions() {
      return this.questions.filter((q) => q.type === 1);
    },
    totalCount() {
      return this.questions.length;
    },
    knowledgeCount() {
      return this.knowledgeQuestions.length;
    },
    vocabCount() {
      return this.vocabQuestions.length;
    },

    relatedVocabList() {
      if (!this.currentKnowledge) return [];
      return this.questions.filter((q) => q.type === 1 && q.parent_id === this.currentKnowledge.id);
    },

    canSubmitKnowledge() {
      if (!this.currentKnowledge) return false;
      if (this.hasOptions(this.currentKnowledge)) return this.selectedOptions.length > 0;
      return String(this.knowledgeInput || "").trim().length > 0;
    },

    modeText() {
      if (this.mode === "exam") return "考试模式";
      if (this.mode === "wrong") return "错题集";
      if (this.mode === "favorite") return "收藏夹";
      return "学习模式";
    },
  },
  methods: {
    goBack() {
      if (this.$router) this.$router.back();
      else window.history.back();
    },

    hasOptions(q) {
      return q && q.options && Object.keys(q.options).length > 0;
    },

    switchMode(m) {
      this.mode = m;
      this.started = false;
      this.sessionList = [];
      this.sessionKnowledgeList = [];
      this.currentIndex = 0;
      this.resetKnowledgeState();
    },

    onConfirm() {
      let pool = this.questions.slice();

      if (this.mode === "wrong") {
        const wrongIds = JSON.parse(localStorage.getItem(WRONG_KG_KEY) || "[]");
        pool = this.questions.filter((q) => q.type === 0 && wrongIds.includes(q.id));
      } else if (this.mode === "favorite") {
        const kgIds = JSON.parse(localStorage.getItem(FAVORITE_KG_KEY) || "[]");
        const vocIds = JSON.parse(localStorage.getItem(FAVORITE_VOC_KEY) || "[]");
        pool = this.questions.filter((q) => kgIds.includes(q.id) || vocIds.includes(q.id));
      } else {
        if (this.questionType === "knowledge") pool = pool.filter((q) => q.type === 0);
        if (this.questionType === "vocab") pool = pool.filter((q) => q.type === 1);
      }

      const count = Number(this.questionCount);
      if (Number.isFinite(count) && count > 0) pool = pool.slice(0, count);

      const toNum = (id) => {
        const m = String(id).match(/\d+/);
        return m ? Number(m[0]) : 0;
      };
      pool = pool.slice().sort((a, b) => toNum(a.id) - toNum(b.id));

      if (this.mode === "study") {
        const kg = pool.filter((q) => q.type === 0);
        this.sessionKnowledgeList = kg;
        this.sessionList = kg;
      } else {
        this.sessionList = pool;
        this.sessionKnowledgeList = pool.filter((q) => q.type === 0);
      }

      this.started = true;
      this.currentIndex = 0;
      this.showRelatedVocab = false;
      this.resetKnowledgeState();
    },

    onReset() {
      this.started = false;
      this.sessionList = [];
      this.sessionKnowledgeList = [];
      this.currentIndex = 0;
      this.showRelatedVocab = false;
      this.resetKnowledgeState();
    },

    nextQuestion() {
      if (this.currentIndex < this.sessionKnowledgeList.length - 1) {
        this.currentIndex++;
        this.resetKnowledgeState();
        this.showRelatedVocab = false;
      }
    },
    preQuestion() {
      if (this.currentIndex > 0) {
        this.currentIndex--;
        this.resetKnowledgeState();
        this.showRelatedVocab = false;
      }
    },

    jumpToKnowledge(id) {
      const idx = this.sessionKnowledgeList.findIndex((q) => q.id === id);
      this.mode = "study";
      this.started = true;
      if (idx >= 0) this.currentIndex = idx;
      this.resetKnowledgeState();
    },

    toggleOption(key) {
      if (this.kgSubmitted) return;

      if (!this.isMultiChoice) {
        this.selectedOptions = [key];
        return;
      }

      const idx = this.selectedOptions.indexOf(key);
      if (idx >= 0) this.selectedOptions.splice(idx, 1);
      else this.selectedOptions.push(key);
    },

    resetKnowledgeState() {
      this.selectedOptions = [];
      this.knowledgeInput = "";
      this.kgSubmitted = false;
      this.kgIsCorrect = null;
    },

    submitKnowledge() {
      if (!this.currentKnowledge) return;
      this.kgSubmitted = true;

      const ans = this.currentKnowledge.answer;

      if (this.hasOptions(this.currentKnowledge)) {
        const correctArr = (Array.isArray(ans) ? ans : [ans]).map((x) => String(x));
        const userArr = (this.selectedOptions || []).map((x) => String(x));

        const correctSet = new Set(correctArr);
        const userSet = new Set(userArr);

        let ok = correctSet.size === userSet.size;
        if (ok) {
          for (const x of correctSet) {
            if (!userSet.has(x)) {
              ok = false;
              break;
            }
          }
        }
        this.kgIsCorrect = ok;
      } else {
        const input = String(this.knowledgeInput || "").trim().toLowerCase();
        if (Array.isArray(ans)) {
          this.kgIsCorrect = ans.map(String).some((a) => a.trim().toLowerCase() === input);
        } else {
          this.kgIsCorrect = String(ans || "").trim().toLowerCase() === input;
        }
      }

      if (this.kgIsCorrect === false) {
        const wrong = JSON.parse(localStorage.getItem(WRONG_KG_KEY) || "[]");
        if (!wrong.includes(this.currentKnowledge.id)) wrong.push(this.currentKnowledge.id);
        localStorage.setItem(WRONG_KG_KEY, JSON.stringify(wrong));
        this.wrongCount = wrong.length;
      }
    },

    showAnswerText(q) {
      if (!q) return "";
      if (q.answer == null) return "（无答案）";
      if (Array.isArray(q.answer)) return `答案: ${q.answer.join(", ")}`;
      return `答案: ${String(q.answer)}`;
    },

    isFavKnowledge(id) {
      return this.favKg.includes(id);
    },
    isFavVocab(id) {
      return this.favVoc.includes(id);
    },
    toggleFavoriteKnowledge(id) {
      const idx = this.favKg.indexOf(id);
      if (idx >= 0) this.favKg.splice(idx, 1);
      else this.favKg.push(id);
      localStorage.setItem(FAVORITE_KG_KEY, JSON.stringify(this.favKg));
      this.favoriteCount = this.favKg.length + this.favVoc.length;
    },
    toggleFavoriteVocab(id) {
      const idx = this.favVoc.indexOf(id);
      if (idx >= 0) this.favVoc.splice(idx, 1);
      else this.favVoc.push(id);
      localStorage.setItem(FAVORITE_VOC_KEY, JSON.stringify(this.favVoc));
      this.favoriteCount = this.favKg.length + this.favVoc.length;
    },

    peekAnswer(vocabId) {
      // Vue2 兼容写法
      if (this.$set) this.$set(this.peekVocab, vocabId, !this.peekVocab[vocabId]);
      else this.peekVocab[vocabId] = !this.peekVocab[vocabId];
    },

    formatVocabAnswer(answer) {
      if (answer == null) return "";
      if (Array.isArray(answer)) return answer.join(" / ");
      return String(answer);
    },
  },

  mounted() {
    // 确保 questionsJson 是数组
    this.questions = Array.isArray(questionsJson) ? questionsJson : [];

    if (localStorage.getItem(FAVORITE_KG_KEY) === null) localStorage.setItem(FAVORITE_KG_KEY, "[]");
    if (localStorage.getItem(FAVORITE_VOC_KEY) === null) localStorage.setItem(FAVORITE_VOC_KEY, "[]");
    if (localStorage.getItem(WRONG_KG_KEY) === null) localStorage.setItem(WRONG_KG_KEY, "[]");

    this.favKg = JSON.parse(localStorage.getItem(FAVORITE_KG_KEY) || "[]");
    this.favVoc = JSON.parse(localStorage.getItem(FAVORITE_VOC_KEY) || "[]");

    this.favoriteCount = this.favKg.length + this.favVoc.length;
    this.wrongCount = JSON.parse(localStorage.getItem(WRONG_KG_KEY) || "[]").length;
  },
};
</script>

<style scoped>
