<template>
  <div class="quiz">
    <h1>HTMLプロフェショナル認定試験 Level2</h1>

    <!-- 还没开始答题时的设置区 -->
    <div v-if="!quizStarted" class="setting">
      <p>请选择本次要答的题目数量（默认全部题目）：</p>
      <input
        type="number"
        v-model.number="selectedCount"
        :min="1"
        :max="questions.length"
        placeholder="留空 = 全部题目"
      />

      <div class="setting-buttons">
        <button @click="startQuiz('normal')">
          开始正常练习（全部题库）
        </button>
        <button @click="startQuiz('wrong')">
          只做错题练习
        </button>
      </div>

      <p class="tips">
        当前总题数：{{ questions.length }} 题。<br>
        已记录错题数量：{{ wrongCount }} 题（保存在浏览器 localStorage）。
      </p>

      <p v-if="noQuestionsMessage" class="warn">
        {{ noQuestionsMessage }}
      </p>
    </div>

    <!-- 进入答题后的主体部分 -->
    <div v-else>
      <!-- 还有题目时 -->
      <div v-if="currentQuestion">
        <p class="q-no">
          第 {{ currentIndex + 1 }} 题 / 本次共 {{ totalQuestions }} 题
        </p>

        <!-- 提示当前是单选还是多选 -->
        <p class="mode-note">
          <strong>题号{{ currentQuestion.id }}</strong>：
          <strong v-if="currentQuestion.answer && currentQuestion.answer.length > 1">
            多选题（请选择所有正确选项）
          </strong>
          <strong v-else>
            单选题
          </strong>
        </p>

        <div class="question-block">
          <!-- 普通文字 -->
          <p class="q-text" v-if="!currentQuestion.description_pre">
            {{ currentQuestion.description }}
          </p>

          <!-- 如果有代码题 -->
          <div v-else>
            <p class="q-text">{{ currentQuestion.description }}</p>
            <pre class="code-block">
{{ currentQuestion.description_pre }}
            </pre>
          </div>
        </div>

        <ul class="options">
          <li
            v-for="(opt, idx) in currentQuestion.options"
            :key="idx"
          >
            <button
              :disabled="answered"
              @click="toggleOption(opt)"
              :class="buttonClass(opt)"
            >
              <pre >{{ opt }}</pre>
            </button>
          </li>
        </ul>

        <!-- 确认答案区：多选/单选都要点“确认答案” -->
        <div v-if="!answered" class="confirm-area">
          <p
            v-if="currentQuestion.answer && currentQuestion.answer.length > 1"
            class="multi-note"
          >
            ※ 本题为多选，请选择所有正确选项后再点击「确认答案」。
          </p>
          <button
            class="confirm-btn"
            @click="submitAnswer"
            :disabled="selectedOptions.length === 0"
          >
            确认答案
          </button>
        </div>

        <div v-if="answered" class="result">
          <p v-if="isCorrect">✅ 回答正确！</p>
          <p v-else>
            ❌ 回答错误。正确答案：
            {{ currentQuestion.answer.join(", ") }}
          </p>

          <h3>{{ currentQuestion.solutionTitle }}</h3>
          <pre>{{ currentQuestion.solutionText }}</pre>

          <button class="next-btn" @click="nextQuestion">
            下一题
          </button>
        </div>
      </div>

      <!-- 题目做完后，显示成绩 -->
      <div v-else class="summary">
        <h2>本次练习结束 🎉</h2>
        <p>本次共 {{ totalQuestions }} 题。</p>
        <p>答对 {{ correctCount }} 题，答错 {{ totalQuestions - correctCount }} 题。</p>
        <p>
          得分：
          {{ scorePercent }} %
          （合格线：70%）
        </p>
        <p v-if="isPassed" class="pass">✅ 恭喜，合格！</p>
        <p v-else class="fail">❌ 未达到合格线，加油再来一轮！</p>

        <p class="tips">
          错题已自动记录。以后可以点击「只做错题练习」专门复习，<br>
          某道错题答对后，会从错题列表中自动删除。
        </p>

        <button @click="resetQuiz">
          返回设置 / 再来一轮
        </button>
      </div>
    </div>
  </div>
</template>

<script>
// 读取题库
import questions from "@/assets/data/htmlQuestions.json";

const WRONG_KEY = "html_wrong_questions_ids";

export default {
  name: "HtmlQuiz",
  data() {
    return {
      questions,                // 全部题目
      quizStarted: false,       // 是否已经开始
      quizMode: "normal",       // normal / wrong
      questionOrder: [],        // 本次练习用的题目索引数组
      totalQuestions: 0,        // 本次总题数
      currentIndex: 0,          // 当前题序（在本次练习中的位置）
      selectedOptions: [],      // 当前题被选择的选项（支持多选）
      answered: false,
      correctCount: 0,
      selectedCount: null,      // 用户输入的题目数量
      noQuestionsMessage: ""    // 没题时的提示信息
    };
  },
  computed: {
    // 当前题目：根据 questionOrder 取题
    currentQuestion() {
      if (
        !this.quizStarted ||
        this.currentIndex < 0 ||
        this.currentIndex >= this.questionOrder.length
      ) {
        return null;
      }
      const realIndex = this.questionOrder[this.currentIndex];
      return this.questions[realIndex];
    },
    // 当前题是否正确（支持单选 & 多选）
    isCorrect() {
      if (!this.currentQuestion) return false;
      const correctAnswers = this.currentQuestion.answer || [];
      const chosen = this.selectedOptions || [];

      // 没选任何选项 → 一定不对
      if (chosen.length === 0) return false;

      // 数量不一致 → 一定不对（处理多选/漏选/多选）
      if (chosen.length !== correctAnswers.length) return false;

      // 比较集合是否一样（顺序无关）
      return correctAnswers.every(ans => chosen.includes(ans));
    },
    // 当前错题数量（从 localStorage 读）
    wrongCount() {
      return this.loadWrongQuestionIds().length;
    },
    // 本次得分百分比
    scorePercent() {
      if (this.totalQuestions === 0) return 0;
      return Math.round((this.correctCount / this.totalQuestions) * 100);
    },
    // 是否合格（>= 70%）
    isPassed() {
      return this.scorePercent >= 70;
    }
  },
  methods: {
    // 开始一轮练习（normal = 全部题库，wrong = 错题练习）
    startQuiz(mode) {
      this.quizMode = mode;
      this.quizStarted = false;          // 先重置，防止旧状态闪一下
      this.noQuestionsMessage = "";
      this.correctCount = 0;
      this.currentIndex = 0;
      this.selectedOptions = [];
      this.answered = false;

      let poolIndexes = [];

      if (mode === "normal") {
        // 所有题目的索引 [0,1,2,...]
        poolIndexes = this.questions.map((_, idx) => idx);
      } else if (mode === "wrong") {
        // 从 wrong ID 列表里取题
        const wrongIds = this.loadWrongQuestionIds();
        poolIndexes = wrongIds
          .map(id => this.questions.findIndex(q => q.id === id))
          .filter(idx => idx !== -1);
      }

      if (poolIndexes.length === 0) {
        this.noQuestionsMessage =
          mode === "wrong"
            ? "目前没有记录的错题，可以先做一次正常练习。"
            : "题库为空，请先添加题目。";
        return;
      }

      // 打乱题目顺序（Fisher–Yates 洗牌）
      for (let i = poolIndexes.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [poolIndexes[i], poolIndexes[j]] = [poolIndexes[j], poolIndexes[i]];
      }

      // 计算本次要做多少题：用户输入 or 全部
      let count = poolIndexes.length;
      if (this.selectedCount && this.selectedCount > 0) {
        count = Math.min(this.selectedCount, poolIndexes.length);
      }

      this.questionOrder = poolIndexes.slice(0, count);

        // ---- 随机打乱每题选项顺序 ----
        this.questionOrder.forEach(index => {
            const q = this.questions[index];
            if (!q._shuffled) {
            q.options = [...q.options].sort(() => Math.random() - 0.5);
            q._shuffled = true;
            }
        });

        this.totalQuestions = this.questionOrder.length;
        this.quizStarted = true;
    },

    // 选择/取消选择一个选项（支持多选）
    toggleOption(opt) {
      if (this.answered || !this.currentQuestion) return;
      const index = this.selectedOptions.indexOf(opt);
      if (index >= 0) {
        // 已选中 → 取消选择
        this.selectedOptions.splice(index, 1);
      } else {
        // 未选中 → 选中
        this.selectedOptions.push(opt);
      }
    },

    // 提交当前题答案
    submitAnswer() {
      if (this.answered || !this.currentQuestion) return;
      if (this.selectedOptions.length === 0) return;

      this.answered = true;

      const currentId = this.currentQuestion.id;
      const correct = this.isCorrect;

      if (correct) {
        this.correctCount++;
      }

      // 更新错题列表：整题判断，答错加入，答对删除
      this.updateWrongList(currentId, correct);
    },

    nextQuestion() {
      if (this.currentIndex < this.questionOrder.length - 1) {
        this.currentIndex++;
        this.selectedOptions = [];
        this.answered = false;
      } else {
        // 做完所有题，currentQuestion 变为 null，进入成绩界面
        this.currentIndex++;
      }
    },

    buttonClass(opt) {
      // 作答前：选中的高亮为 selected
      if (!this.answered) {
        return this.selectedOptions.includes(opt) ? "selected" : "";
      }

      // 作答后：显示正确/错误
      const correctAnswers = this.currentQuestion
        ? this.currentQuestion.answer || []
        : [];

      if (correctAnswers.includes(opt)) {
        // 正确选项 → 绿色
        return "correct";
      }

      if (this.selectedOptions.includes(opt) && !correctAnswers.includes(opt)) {
        // 用户选了，但其实是错的 → 红色
        return "wrong";
      }

      return "";
    },

    // 重新回到设置界面
    resetQuiz() {
      this.quizStarted = false;
      this.currentIndex = 0;
      this.selectedOptions = [];
      this.answered = false;
      this.totalQuestions = 0;
      this.correctCount = 0;
    },

    // ---- 错题列表相关（用 localStorage 模拟“错题文档”） ----
    loadWrongQuestionIds() {
      const raw = localStorage.getItem(WRONG_KEY);
      if (!raw) return [];
      try {
        const arr = JSON.parse(raw);
        return Array.isArray(arr) ? arr : [];
      } catch (e) {
        return [];
      }
    },
    saveWrongQuestionIds(ids) {
      localStorage.setItem(WRONG_KEY, JSON.stringify(ids));
    },
    updateWrongList(id, isCorrect) {
      let ids = this.loadWrongQuestionIds();
      if (!isCorrect) {
        // 答错：加入列表（避免重复）
        if (!ids.includes(id)) {
          ids.push(id);
        }
      } else {
        // 答对：从列表中删除该题
        ids = ids.filter(x => x !== id);
      }
      this.saveWrongQuestionIds(ids);
    }
  }
};
</script>

<style scoped>
.quiz {
  max-width: 800px;
  margin: 0 auto;
  padding: 16px;
  text-align: left;
}
.setting {
  border: 1px solid #ddd;
  padding: 16px;
  border-radius: 8px;
}
.setting input {
  padding: 6px 8px;
  margin-top: 4px;
  margin-bottom: 12px;
  width: 200px;
}
.setting-buttons button {
  margin-right: 8px;
  margin-bottom: 8px;
}
.tips {
  font-size: 13px;
  color: #666;
}
.warn {
  color: #c0392b;
  margin-top: 8px;
}
.q-no {
  font-size: 14px;
  color: #555;
}
.mode-note {
  font-size: 13px;
  color: #555;
  margin-bottom: 4px;
}
.q-text {
  font-size: 18px;
  margin: 12px 0;
}
.question-block {
  margin-bottom: 8px;
}
.code-block {
  background: #f4f4f4;
  padding: 10px;
  border-radius: 6px;
  overflow-x: auto;
  border-left: 4px solid #42b983;
  font-size: 14px;
  white-space: pre-wrap;
}
.options {
  list-style: none;
  padding: 0;
}
.options li {
  margin-bottom: 8px;
}
button {
  padding: 6px 12px;
  border-radius: 4px;
  border: 1px solid #ccc;
  cursor: pointer;
  width: 98%;
  text-align: left;
}
button.selected {
  background: #f7f7f7;
  border-color: #888;
}
button.correct {
  border-color: green;
}
button.wrong {
  border-color: red;
}
.result {
  margin-top: 16px;
  padding-top: 12px;
  border-top: 1px solid #ddd;
}
.next-btn {
  margin-top: 8px;
}
.summary {
  border-top: 1px solid #ddd;
  margin-top: 16px;
  padding-top: 12px;
}
.pass {
  color: green;
  font-weight: bold;
}
.fail {
  color: #c0392b;
  font-weight: bold;
}
.confirm-area {
  margin-top: 12px;
}
.confirm-btn {
  padding: 6px 16px;
  border-radius: 4px;
  border: 1px solid #42b983;
  background: #42b983;
  color: #fff;
  cursor: pointer;
}
.confirm-btn:disabled {
  opacity: 0.6;
  cursor: not-allowed;
}
.multi-note {
  font-size: 13px;
  color: #c0392b;
  margin-bottom: 4px;
}
</style>
