<template>
  <div class="quiz">
    <h1>{{ msg || "PostgreSQL 认证考试练习" }}</h1>

    <div v-if="!quizStarted" class="setting">
      <p>输入本次想练习的题目数量，并选择按顺序或乱序出题；不填默认使用全部题目。</p>
      <input
        type="number"
        v-model.number="selectedCount"
        :min="1"
        :max="questions.length"
        placeholder="题目数量"
      />

      <div class="order-setting">
        <span class="setting-label">出题顺序</span>
        <label class="order-option">
          <input
            v-model="questionOrderMode"
            type="radio"
            value="sequential"
          />
          按顺序
        </label>
        <label class="order-option">
          <input
            v-model="questionOrderMode"
            type="radio"
            value="random"
          />
          乱序
        </label>
      </div>

      <div
        v-if="questionOrderMode === 'sequential'"
        class="start-setting"
      >
        <span class="setting-label">开始位置</span>
        <label class="order-option">
          <input
            v-model="sequentialStartMode"
            type="radio"
            value="beginning"
          />
          从头开始
        </label>
        <label class="order-option">
          <input
            v-model="sequentialStartMode"
            type="radio"
            value="resume"
            :disabled="!lastSequentialResumeId"
          />
          从上次做到的位置继续
        </label>
        <label class="order-option">
          <input
            v-model="sequentialStartMode"
            type="radio"
            value="manual"
          />
          指定题号开始
        </label>

        <p
          v-if="lastSequentialResumeId"
          class="tips start-tip"
        >
          上次做到：{{ lastSequentialResumeId }}
        </p>
        <p
          v-else
          class="tips start-tip"
        >
          还没有上次顺序练习进度，第一次会从头开始。
        </p>

        <input
          v-if="sequentialStartMode === 'manual'"
          v-model.trim="manualStartInput"
          type="text"
          class="start-input"
          placeholder="例如 12 或 pg00010012"
        />
        <p
          v-else-if="sequentialStartMode === 'resume' && lastSequentialResumeId"
          class="tips start-tip"
        >
          继续时会从 {{ lastSequentialResumeId }} 开始按顺序出题。
        </p>
      </div>

      <div class="setting-buttons">
        <button @click="startQuiz('normal')">
          开始普通练习
        </button>
        <button @click="startQuiz('wrong')">
          只刷错题
        </button>
      </div>

      <p class="tips">
        当前题库共 {{ questions.length }} 题。<br>
        错题本中有 {{ wrongCount }} 题，数据保存在浏览器的 localStorage。
      </p>

      <p v-if="noQuestionsMessage" class="warn">
        {{ noQuestionsMessage }}
      </p>
    </div>

    <div v-else>
      <div v-if="currentQuestion">
        <p class="q-no">
          第 {{ currentIndex + 1 }} 题 / 共 {{ totalQuestions }} 题
        </p>

        <p v-if="currentQuestion.category" class="category">
          分类：{{ currentQuestion.category }}
        </p>

        <p class="mode-note">
          <strong>题号 {{ currentQuestion.id }}</strong>。
          <strong v-if="currentQuestion.answer && currentQuestion.answer.length > 1">
            这是一道多选题，请把所有正确答案都选出来。
          </strong>
          <strong v-else>
            这是一道单选题。
          </strong>
        </p>

        <div class="question-block">
          <p class="q-text">
            {{ currentQuestion.description }}
          </p>

          <pre
            v-if="currentQuestion.description_pre"
            class="code-block"
          >
{{ currentQuestion.description_pre }}
          </pre>

          <div
            v-if="currentQuestion.questionTables && currentQuestion.questionTables.length > 0"
            class="table-stack"
          >
            <div
              v-for="(table, tableIdx) in currentQuestion.questionTables"
              :key="`question-table-${tableIdx}`"
              class="rich-table-card"
            >
              <p
                v-if="table.title"
                class="table-caption"
              >
                {{ table.title }}
              </p>
              <div class="table-scroll">
                <table class="schema-table">
                  <thead>
                    <tr>
                      <th
                        v-for="(header, headerIdx) in table.headers"
                        :key="`question-header-${tableIdx}-${headerIdx}`"
                      >
                        {{ header }}
                      </th>
                    </tr>
                  </thead>
                  <tbody>
                    <tr
                      v-for="(row, rowIdx) in table.rows"
                      :key="`question-row-${tableIdx}-${rowIdx}`"
                    >
                      <td
                        v-for="(cell, cellIdx) in row"
                        :key="`question-cell-${tableIdx}-${rowIdx}-${cellIdx}`"
                      >
                        {{ cell }}
                      </td>
                    </tr>
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        </div>

        <ul class="options">
          <li
            v-for="(opt, idx) in currentOptions"
            :key="opt.value || idx"
          >
            <button
              :disabled="answered"
              @click="toggleOption(opt)"
              :class="buttonClass(opt)"
            >
              <div class="option-card">
                <p
                  v-if="opt.label || (opt.text && !isMultilineText(opt.text))"
                  class="option-line"
                >
                  <strong v-if="opt.label">{{ opt.label }}</strong>
                  <span v-if="opt.text && !isMultilineText(opt.text)">
                    {{ opt.text }}
                  </span>
                </p>

                <div
                  v-if="opt.text && isMultilineText(opt.text)"
                  class="option-multiline"
                >
                  <strong v-if="opt.label">{{ opt.label }}</strong>
                  <pre class="option-pre">{{ opt.text }}</pre>
                </div>

                <p
                  v-if="opt.note"
                  class="option-note"
                >
                  {{ opt.note }}
                </p>

                <div
                  v-if="opt.tables && opt.tables.length > 0"
                  class="table-stack option-table-stack"
                >
                  <div
                    v-for="(table, tableIdx) in opt.tables"
                    :key="`${opt.value}-table-${tableIdx}`"
                    class="rich-table-card"
                  >
                    <p
                      v-if="table.title"
                      class="table-caption"
                    >
                      {{ table.title }}
                    </p>
                    <div class="table-scroll">
                      <table class="schema-table">
                        <thead>
                          <tr>
                            <th
                              v-for="(header, headerIdx) in table.headers"
                              :key="`${opt.value}-header-${tableIdx}-${headerIdx}`"
                            >
                              {{ header }}
                            </th>
                          </tr>
                        </thead>
                        <tbody>
                          <tr
                            v-for="(row, rowIdx) in table.rows"
                            :key="`${opt.value}-row-${tableIdx}-${rowIdx}`"
                          >
                            <td
                              v-for="(cell, cellIdx) in row"
                              :key="`${opt.value}-cell-${tableIdx}-${rowIdx}-${cellIdx}`"
                            >
                              {{ cell }}
                            </td>
                          </tr>
                        </tbody>
                      </table>
                    </div>
                  </div>
                </div>
              </div>
            </button>
          </li>
        </ul>

        <div v-if="!answered" class="confirm-area">
          <p
            v-if="currentQuestion.answer && currentQuestion.answer.length > 1"
            class="multi-note"
          >
            多选题需要把全部正确答案都选中，再点击“提交答案”。
          </p>
          <button
            class="confirm-btn"
            @click="submitAnswer"
            :disabled="selectedOptions.length === 0"
          >
            提交答案
          </button>
        </div>

        <div v-if="answered" class="result">
          <p v-if="isCorrect">答对了。</p>
          <p v-else>
            这题答错了，正确答案是：
            {{ correctAnswerDisplay }}
          </p>

          <h3>{{ currentQuestion.solutionTitle }}</h3>
          <pre>{{ currentQuestion.solutionText }}</pre>

          <div
            v-if="currentQuestion.solutionTables && currentQuestion.solutionTables.length > 0"
            class="table-stack solution-table-stack"
          >
            <div
              v-for="(table, tableIdx) in currentQuestion.solutionTables"
              :key="`solution-table-${tableIdx}`"
              class="rich-table-card"
            >
              <p
                v-if="table.title"
                class="table-caption"
              >
                {{ table.title }}
              </p>
              <div class="table-scroll">
                <table class="schema-table">
                  <thead>
                    <tr>
                      <th
                        v-for="(header, headerIdx) in table.headers"
                        :key="`solution-header-${tableIdx}-${headerIdx}`"
                      >
                        {{ header }}
                      </th>
                    </tr>
                  </thead>
                  <tbody>
                    <tr
                      v-for="(row, rowIdx) in table.rows"
                      :key="`solution-row-${tableIdx}-${rowIdx}`"
                    >
                      <td
                        v-for="(cell, cellIdx) in row"
                        :key="`solution-cell-${tableIdx}-${rowIdx}-${cellIdx}`"
                      >
                        {{ cell }}
                      </td>
                    </tr>
                  </tbody>
                </table>
              </div>
            </div>
          </div>

          <button class="next-btn" @click="nextQuestion">
            下一题
          </button>
        </div>
      </div>

      <div v-else class="summary">
        <h2>本次练习结束</h2>
        <p>本次共 {{ totalQuestions }} 题。</p>
        <p>答对 {{ correctCount }} 题，答错 {{ totalQuestions - correctCount }} 题。</p>
        <p>
          正确率 {{ scorePercent }} %
          （及格线 70%）
        </p>
        <p v-if="isPassed" class="pass">本次练习已达及格线。</p>
        <p v-else class="fail">还没过线，再刷一轮就更稳了。</p>

        <p class="tips">
          这次做错的题会自动进入错题本，下次可以直接点“只刷错题”。<br>
          之后你把 PostgreSQL 真题或知识点发我，我会继续按这个格式帮你补题。
        </p>

        <button @click="resetQuiz">
          重新开始
        </button>
      </div>
    </div>
  </div>
</template>

<script>
import questions from "@/assets/data/postgresqlQuestions.json";

const WRONG_KEY = "postgresql_wrong_questions_ids";
const SEQUENTIAL_RESUME_KEY = "postgresql_sequential_resume_question_id";

export default {
  name: "PostgreSqlQuiz",
  props: {
    msg: String
  },
  data() {
    return {
      questions,
      quizStarted: false,
      quizMode: "normal",
      questionOrder: [],
      questionOrderMode: "random",
      sequentialStartMode: "beginning",
      totalQuestions: 0,
      currentIndex: 0,
      selectedOptions: [],
      answered: false,
      correctCount: 0,
      selectedCount: null,
      manualStartInput: "",
      lastSequentialResumeId: "",
      noQuestionsMessage: ""
    };
  },
  computed: {
    currentQuestion() {
      if (
        !this.quizStarted ||
        this.currentIndex < 0 ||
        this.currentIndex >= this.questionOrder.length
      ) {
        return null;
      }
      const realIndex = this.questionOrder[this.currentIndex];
      return this.questions[realIndex];
    },
    currentOptions() {
      if (!this.currentQuestion || !Array.isArray(this.currentQuestion.options)) {
        return [];
      }
      return this.currentQuestion.options.map((opt, idx) =>
        this.normalizeOption(opt, idx)
      );
    },
    isCorrect() {
      if (!this.currentQuestion) return false;
      const correctAnswers = this.currentQuestion.answer || [];
      const chosen = this.selectedOptions || [];

      if (chosen.length === 0) return false;
      if (chosen.length !== correctAnswers.length) return false;

      return correctAnswers.every((ans) => chosen.includes(ans));
    },
    wrongCount() {
      return this.loadWrongQuestionIds().length;
    },
    scorePercent() {
      if (this.totalQuestions === 0) return 0;
      return Math.round((this.correctCount / this.totalQuestions) * 100);
    },
    isPassed() {
      return this.scorePercent >= 70;
    },
    correctAnswerDisplay() {
      if (!this.currentQuestion || !Array.isArray(this.currentQuestion.answer)) {
        return "";
      }

      return this.currentQuestion.answer
        .map((answerValue) => {
          const matchedOption = this.currentOptions.find(
            (opt) => opt.value === answerValue
          );

          if (!matchedOption) {
            return answerValue;
          }

          if (matchedOption.text) {
            return matchedOption.label
              ? `${matchedOption.label} ${matchedOption.text}`
              : matchedOption.text;
          }

          if (matchedOption.note) {
            return matchedOption.label
              ? `${matchedOption.label} ${matchedOption.note}`
              : matchedOption.note;
          }

          return matchedOption.label || matchedOption.value;
        })
        .join(" / ");
    }
  },
  mounted() {
    this.lastSequentialResumeId = this.loadSequentialResumeId();
  },
  methods: {
    startQuiz(mode) {
      this.quizMode = mode;
      this.quizStarted = false;
      this.noQuestionsMessage = "";
      this.correctCount = 0;
      this.currentIndex = 0;
      this.selectedOptions = [];
      this.answered = false;

      let poolIndexes = [];

      if (mode === "normal") {
        poolIndexes = this.questions.map((_, idx) => idx);
      } else if (mode === "wrong") {
        const wrongIds = this.loadWrongQuestionIds();
        poolIndexes = wrongIds
          .map((id) => this.questions.findIndex((q) => q.id === id))
          .filter((idx) => idx !== -1);
      }

      if (poolIndexes.length === 0) {
        this.noQuestionsMessage =
          mode === "wrong"
            ? "错题本还是空的，先刷一轮普通练习吧。"
            : "当前没有可用题目，请先补充 PostgreSQL 题库。";
        return;
      }

      if (this.questionOrderMode === "random") {
        for (let i = poolIndexes.length - 1; i > 0; i--) {
          const j = Math.floor(Math.random() * (i + 1));
          [poolIndexes[i], poolIndexes[j]] = [poolIndexes[j], poolIndexes[i]];
        }
      } else {
        poolIndexes = poolIndexes.slice().sort((a, b) => a - b);
      }

      if (mode === "normal" && this.questionOrderMode === "sequential") {
        const startResult = this.resolveSequentialStart(poolIndexes);
        if (!startResult.ok) {
          this.noQuestionsMessage = startResult.message;
          return;
        }
        poolIndexes = poolIndexes.slice(startResult.startAt);
      }

      if (poolIndexes.length === 0) {
        this.noQuestionsMessage = "从这个位置开始已经没有可练习的题目了。";
        return;
      }

      let count = poolIndexes.length;
      if (this.selectedCount && this.selectedCount > 0) {
        count = Math.min(this.selectedCount, poolIndexes.length);
      }

      this.questionOrder = poolIndexes.slice(0, count);

      this.questionOrder.forEach((index) => {
        const q = this.questions[index];
        if (!q._shuffled) {
          q.options = [...q.options].sort(() => Math.random() - 0.5);
          q._shuffled = true;
        }
      });

      this.totalQuestions = this.questionOrder.length;
      this.quizStarted = true;

      this.persistSequentialProgressForCurrentQuestion();
    },

    toggleOption(opt) {
      if (this.answered || !this.currentQuestion) return;
      const value = this.optionValue(opt);
      const index = this.selectedOptions.indexOf(value);
      if (index >= 0) {
        this.selectedOptions.splice(index, 1);
      } else {
        this.selectedOptions.push(value);
      }
    },

    submitAnswer() {
      if (this.answered || !this.currentQuestion) return;
      if (this.selectedOptions.length === 0) return;

      this.answered = true;

      const currentId = this.currentQuestion.id;
      const correct = this.isCorrect;

      if (correct) {
        this.correctCount++;
      }

      this.updateWrongList(currentId, correct);
    },

    nextQuestion() {
      if (this.currentIndex < this.questionOrder.length - 1) {
        this.currentIndex++;
        this.selectedOptions = [];
        this.answered = false;
        this.persistSequentialProgressForCurrentQuestion();
      } else {
        this.persistSequentialProgressAfterSessionEnd();
        this.currentIndex++;
      }
    },

    buttonClass(opt) {
      const value = this.optionValue(opt);

      if (!this.answered) {
        return this.selectedOptions.includes(value) ? "selected" : "";
      }

      const correctAnswers = this.currentQuestion
        ? this.currentQuestion.answer || []
        : [];

      if (correctAnswers.includes(value)) {
        return "correct";
      }

      if (this.selectedOptions.includes(value) && !correctAnswers.includes(value)) {
        return "wrong";
      }

      return "";
    },
    normalizeOption(opt, idx) {
      if (typeof opt === "string") {
        const matched = opt.match(/^([A-Z])\.\s*([\s\S]*)$/);
        if (matched) {
          return {
            value: opt,
            label: `${matched[1]}.`,
            text: matched[2],
            note: "",
            tables: []
          };
        }

        return {
          value: opt,
          label: "",
          text: opt,
          note: "",
          tables: []
        };
      }

      return {
        value: opt.value || `option-${idx}`,
        label: opt.label || "",
        text: opt.text || "",
        note: opt.note || "",
        tables: Array.isArray(opt.tables) ? opt.tables : []
      };
    },
    optionValue(opt) {
      return typeof opt === "string" ? opt : opt.value;
    },
    isMultilineText(text) {
      return typeof text === "string" && text.includes("\n");
    },

    resetQuiz() {
      this.quizStarted = false;
      this.currentIndex = 0;
      this.selectedOptions = [];
      this.answered = false;
      this.totalQuestions = 0;
      this.correctCount = 0;
    },

    loadWrongQuestionIds() {
      const raw = localStorage.getItem(WRONG_KEY);
      if (!raw) return [];
      try {
        const arr = JSON.parse(raw);
        return Array.isArray(arr) ? arr : [];
      } catch (e) {
        return [];
      }
    },
    loadSequentialResumeId() {
      const raw = localStorage.getItem(SEQUENTIAL_RESUME_KEY);
      return raw || "";
    },
    saveWrongQuestionIds(ids) {
      localStorage.setItem(WRONG_KEY, JSON.stringify(ids));
    },
    saveSequentialResumeId(id) {
      if (!id) return;
      localStorage.setItem(SEQUENTIAL_RESUME_KEY, id);
      this.lastSequentialResumeId = id;
    },
    clearSequentialResumeId() {
      localStorage.removeItem(SEQUENTIAL_RESUME_KEY);
      this.lastSequentialResumeId = "";
    },
    isSequentialNormalMode() {
      return this.quizMode === "normal" && this.questionOrderMode === "sequential";
    },
    resolveSequentialStart(poolIndexes) {
      if (this.sequentialStartMode === "resume") {
        const savedId = this.loadSequentialResumeId();
        if (!savedId) {
          return {
            ok: false,
            message: "还没有可继续的顺序练习进度，请先从头开始做一轮。"
          };
        }

        const questionIndex = this.questions.findIndex((q) => q.id === savedId);
        if (questionIndex === -1) {
          this.clearSequentialResumeId();
          return {
            ok: false,
            message: "上次保存的进度已经找不到对应题目了，请重新从头开始。"
          };
        }

        const startAt = poolIndexes.indexOf(questionIndex);
        if (startAt === -1) {
          return {
            ok: false,
            message: "当前顺序练习无法从上次位置继续，请重新选择开始位置。"
          };
        }

        return { ok: true, startAt };
      }

      if (this.sequentialStartMode === "manual") {
        const input = this.manualStartInput.trim();
        if (!input) {
          return {
            ok: false,
            message: "请输入要开始的题号，例如 12 或 pg00010012。"
          };
        }

        let questionIndex = -1;
        if (/^pg\d+$/i.test(input)) {
          const normalized = input.toLowerCase();
          questionIndex = this.questions.findIndex(
            (q) => q.id.toLowerCase() === normalized
          );
        } else if (/^\d+$/.test(input)) {
          questionIndex = Number(input) - 1;
        }

        if (questionIndex < 0 || questionIndex >= this.questions.length) {
          return {
            ok: false,
            message: "指定题号不在当前题库范围内，请重新输入。"
          };
        }

        const startAt = poolIndexes.indexOf(questionIndex);
        if (startAt === -1) {
          return {
            ok: false,
            message: "这个题号不在当前顺序题单里，请重新输入。"
          };
        }

        return { ok: true, startAt };
      }

      return { ok: true, startAt: 0 };
    },
    persistSequentialProgressForCurrentQuestion() {
      if (!this.isSequentialNormalMode()) return;
      if (this.currentIndex < 0 || this.currentIndex >= this.questionOrder.length) return;

      const questionIndex = this.questionOrder[this.currentIndex];
      const question = this.questions[questionIndex];
      if (question) {
        this.saveSequentialResumeId(question.id);
      }
    },
    persistSequentialProgressAfterSessionEnd() {
      if (!this.isSequentialNormalMode()) return;
      if (this.questionOrder.length === 0) return;

      const lastQuestionIndex = this.questionOrder[this.questionOrder.length - 1];
      const nextQuestionIndex = lastQuestionIndex + 1;

      if (nextQuestionIndex < this.questions.length) {
        this.saveSequentialResumeId(this.questions[nextQuestionIndex].id);
      } else {
        this.clearSequentialResumeId();
      }
    },
    updateWrongList(id, isCorrect) {
      let ids = this.loadWrongQuestionIds();
      if (!isCorrect) {
        if (!ids.includes(id)) {
          ids.push(id);
        }
      } else {
        ids = ids.filter((x) => x !== id);
      }
      this.saveWrongQuestionIds(ids);
    }
  }
};
</script>

<style scoped>
.quiz {
  max-width: 800px;
  margin: 0 auto;
  padding: 16px;
  text-align: left;
}
.setting {
  border: 1px solid #ddd;
  padding: 16px;
  border-radius: 8px;
}
.setting input {
  padding: 6px 8px;
  margin-top: 4px;
  margin-bottom: 12px;
  width: 200px;
}
.order-setting {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 12px;
  flex-wrap: wrap;
}
.start-setting {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 12px;
  flex-wrap: wrap;
}
.setting-label {
  font-weight: bold;
}
.order-option {
  display: inline-flex;
  align-items: center;
  gap: 6px;
}
.start-input {
  width: 240px;
}
.start-tip {
  width: 100%;
  margin-top: -4px;
  margin-bottom: 0;
}
.setting-buttons button {
  margin-right: 8px;
  margin-bottom: 8px;
}
.tips {
  font-size: 13px;
  color: #666;
}
.warn {
  color: #c0392b;
  margin-top: 8px;
}
.q-no,
.category {
  font-size: 14px;
  color: #555;
}
.mode-note {
  font-size: 13px;
  color: #555;
  margin-bottom: 4px;
}
.q-text {
  font-size: 18px;
  margin: 12px 0;
}
.question-block {
  margin-bottom: 8px;
}
.code-block {
  background: #f4f4f4;
  padding: 10px;
  border-radius: 6px;
  overflow-x: auto;
  border-left: 4px solid #42b983;
  font-size: 14px;
