<template>
  <div id="app">
    <div v-if="!isAuthenticated" class="auth-shell">
      <div class="auth-card">
        <h1 class="auth-title">Learning Doujyou</h1>
        <p class="auth-subtitle">Sign in before viewing the content.</p>

        <form class="auth-form" @submit.prevent="login">
          <label class="auth-label" for="username">Username</label>
          <input
            id="username"
            v-model.trim="username"
            class="auth-input"
            type="text"
            autocomplete="username"
            placeholder="Enter username"
          />

          <label class="auth-label" for="password">Password</label>
          <input
            id="password"
            v-model="password"
            class="auth-input"
            type="password"
            autocomplete="current-password"
            placeholder="Enter password"
          />

          <p v-if="authError" class="auth-error">{{ authError }}</p>

          <button class="auth-button" type="submit">Sign in</button>
        </form>
      </div>
    </div>

    <div v-else>
      <div class="toolbar">
        <button
          v-if="activePage !== 'home'"
          class="home-button"
          @click="activePage = 'home'"
        >
          Back Home
        </button>

        <button class="logout-button" @click="logout">
          Log out
        </button>
      </div>

      <HelloWorld
        v-if="activePage === 'home'"
        msg="IT Study Hub"
        error=""
        @open-html="activePage = 'html'"
        @open-itkenshi="activePage = 'itkenshi'"
        @open-postgresql="activePage = 'postgresql'"
        @open-servicenow="activePage = 'servicenow'"
      />

      <HtmlQuiz
        v-if="activePage === 'html'"
        msg="HTML Study"
      />

      <ServiceNowQuiz
        v-if="activePage === 'servicenow'"
        msg="ServiceNow CSA Practice"
      />

      <ITKenshiQuiz
        v-if="activePage === 'itkenshi'"
        msg="IT剣士 项目理解题库"
      />

      <PostgreSqlQuiz
        v-if="activePage === 'postgresql'"
        msg="PostgreSQL Study"
      />
    </div>
  </div>
</template>

<script>
import HelloWorld from "./components/HelloWorld.vue";
import HtmlQuiz from "./components/HtmlQuiz.vue";
import ITKenshiQuiz from "./components/ITKenshiQuiz.vue";
import PostgreSqlQuiz from "./components/PostgreSqlQuiz.vue";
import ServiceNowQuiz from "./components/ServiceNowQuiz.vue";

const AUTH_USER = "ITKenshi";
const AUTH_PASSWORD = "learning1997";
const AUTH_STORAGE_KEY = "learning_doujyo_authenticated";

export default {
  name: "App",
  components: {
    HelloWorld,
    HtmlQuiz,
    ITKenshiQuiz,
    PostgreSqlQuiz,
    ServiceNowQuiz
  },
  data() {
    return {
      activePage: "home",
      username: "",
      password: "",
      authError: "",
      isAuthenticated:
        typeof window !== "undefined" &&
        window.sessionStorage.getItem(AUTH_STORAGE_KEY) === "true"
    };
  },
  methods: {
    login() {
      if (this.username === AUTH_USER && this.password === AUTH_PASSWORD) {
        this.isAuthenticated = true;
        this.authError = "";
        this.password = "";
        window.sessionStorage.setItem(AUTH_STORAGE_KEY, "true");
        return;
      }

      this.authError = "Incorrect username or password.";
    },
    logout() {
      this.isAuthenticated = false;
      this.username = "";
      this.password = "";
      this.authError = "";
      this.activePage = "home";
      window.sessionStorage.removeItem(AUTH_STORAGE_KEY);
    }
  }
};
</script>

<style scoped>
#app {
  min-height: 100vh;
}

.auth-shell {
  min-height: 100vh;
  display: grid;
  place-items: center;
  padding: 24px;
  background: linear-gradient(135deg, #f8fafc 0%, #dbeafe 100%);
}

.auth-card {
  width: min(100%, 420px);
  padding: 32px;
  border-radius: 20px;
  background: rgba(255, 255, 255, 0.96);
  box-shadow: 0 20px 50px rgba(15, 23, 42, 0.12);
}

.auth-title {
  margin: 0 0 8px;
  font-size: 28px;
  color: #0f172a;
}

.auth-subtitle {
  margin: 0 0 24px;
  color: #475569;
}

.auth-form {
  display: grid;
  gap: 12px;
}

.auth-label {
  font-size: 14px;
  color: #334155;
}

.auth-input {
  width: 100%;
  padding: 12px 14px;
  border: 1px solid #cbd5e1;
  border-radius: 12px;
  font-size: 15px;
  outline: none;
}

.auth-input:focus {
  border-color: #2563eb;
  box-shadow: 0 0 0 3px rgba(37, 99, 235, 0.16);
}

.auth-error {
  margin: 4px 0 0;
  color: #dc2626;
  font-size: 14px;
}

.auth-button,
.home-button,
.logout-button {
  padding: 10px 16px;
  border: 1px solid transparent;
  border-radius: 999px;
  cursor: pointer;
  font-size: 14px;
}

.auth-button {
  margin-top: 8px;
  background: #2563eb;
  color: #ffffff;
}

.auth-button:hover {
  background: #1d4ed8;
}

.toolbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 12px;
  margin-bottom: 16px;
}

.home-button,
.logout-button {
  background: #f8fafc;
  border-color: #cbd5e1;
  color: #1e293b;
}

.home-button:hover,
.logout-button:hover {
  background: #e2e8f0;
}
</style>
